fn object<const N: usize>(entries: [(&'static str, Value); N]) -> Map<String, Value> {
    entries
        .into_iter()
        .map(|(key, value)| (key.to_string(), value))
        .collect()
}

fn query_rules<const N: usize>(
    entries: [(&'static str, QueryRule); N],
) -> BTreeMap<String, QueryRule> {
    entries
        .into_iter()
        .map(|(key, value)| (key.to_string(), value))
        .collect()
}

fn strings<const N: usize>(items: [&'static str; N]) -> Vec<String> {
    items.into_iter().map(str::to_string).collect()
}
